import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Cpu, Activity } from 'lucide-react';

const LiveLogic = ({ socket }) => {
  const [logs, setLogs] = useState([
    { id: 1, status: 'Idle', message: 'System Ready. Awaiting Inputs.', progress: 100 }
  ]);

  useEffect(() => {
    if (!socket) return;

    socket.on('inference-status', (data) => {
      setLogs(prev => [
        { id: Date.now(), ...data },
        ...prev.slice(0, 4)
      ]);
    });

    return () => socket.off('inference-status');
  }, [socket]);

  return (
    <div className="bg-slate-900/50 backdrop-blur-xl border border-white/10 p-6 rounded-3xl h-full flex flex-col gap-6 shadow-2xl">
      <div className="flex items-center gap-3">
        <Cpu className="text-cyan-400 w-6 h-6 animate-pulse" />
        <h3 className="text-xl font-bold text-white tracking-widest uppercase text-xs">AI Live Logic</h3>
      </div>

      <div className="flex-1 overflow-hidden space-y-4">
        <AnimatePresence mode="popLayout">
          {logs.map((log) => (
            <motion.div
              key={log.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, scale: 0.9 }}
              className={`p-4 rounded-2xl border ${
                log.status === 'Complete' 
                ? 'bg-emerald-500/10 border-emerald-500/20' 
                : 'bg-white/5 border-white/5'
              }`}
            >
              <div className="flex justify-between items-center mb-2">
                <span className={`text-[10px] font-bold uppercase tracking-tighter ${
                  log.status === 'Complete' ? 'text-emerald-400' : 'text-cyan-400'
                }`}>
                  {log.status}
                </span>
                <span className="text-[10px] text-white/30">
                  {new Date(log.id).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                </span>
              </div>
              <p className="text-sm text-white/70 font-medium">{log.message}</p>

              {log.progress < 100 && (
                <div className="mt-3 h-1 bg-white/10 rounded-full overflow-hidden">
                  <motion.div 
                    className="h-full bg-cyan-500"
                    initial={{ width: 0 }}
                    animate={{ width: `${log.progress}%` }}
                    transition={{ duration: 0.5 }}
                  />
                </div>
              )}
            </motion.div>
          ))}
        </AnimatePresence>
      </div>

      <div className="pt-4 border-t border-white/5">
        <div className="flex items-center gap-2 text-[10px] text-white/40 uppercase font-bold tracking-widest">
          <Activity className="w-3 h-3" />
          Neural Engine Connected
        </div>
      </div>
    </div>
  );
};

export default LiveLogic;
